13	/*
14	 * Fuzzing harness for committed (named) datatype open and introspection.
15	 *
16	 * Exercises: H5Topen2, H5Tget_class, H5Tget_size, H5Tget_nmembers,
17	 *            H5Tget_member_type, H5Tget_member_offset, H5Tis_variable_str,
18	 *            H5Tclose  — and supporting helpers like H5Tget_super,
19	 *            H5Tget_array_ndims/dims2, H5Tget_member_name.
20	 *
21	 * Attack surface: The committed-type descriptor is stored verbatim in the
22	 * HDF5 file and decoded on H5Topen2.  Compound, enum, vlen, and array type
23	 * descriptors are deeply nested and hand-parsed; historically a rich source
24	 * of OOB/UAF bugs.
25	 */
26	
27	#include "hdf5.h"
28	
29	#include <stdint.h>
30	#include <stdio.h>
31	#include <stdlib.h>
32	#include <string.h>
33	#include <unistd.h>
