35	/* Maximum recursion depth when introspecting nested types */
36	#define MAX_DEPTH 8
37	
38	/* Forward declaration */
39	static void introspect_type(hid_t type_id, int depth);
40	
41	/* Recursively introspect a datatype, honouring API preconditions. */
42	static void introspect_type(hid_t type_id, int depth)
43	{
44	    if (depth >= MAX_DEPTH)
45	        return;
46	    if (type_id < 0)
47	        return;
48	
49	    /* Always valid for any type */
50	    H5T_class_t cls  = H5Tget_class(type_id);
51	    size_t       sz  = H5Tget_size(type_id);
52	    (void)sz;
53	
54	    switch (cls) {
55	
56	    case H5T_COMPOUND: {
57	        int nmembers = H5Tget_nmembers(type_id);
58	        if (nmembers < 0)
59	            break;
60	        for (int i = 0; i < nmembers; i++) {
61	            /* H5Tget_member_name returns malloc'd string; caller must free. */
62	            char *mname = H5Tget_member_name(type_id, (unsigned)i);
63	            if (mname)
64	                H5free_memory(mname);
65	
66	            size_t off = H5Tget_member_offset(type_id, (unsigned)i);
67	            (void)off;
68	
69	            /* H5Tget_member_type returns a new type ID that must be closed. */
70	            hid_t mtype = H5Tget_member_type(type_id, (unsigned)i);
71	            if (mtype >= 0) {
72	                introspect_type(mtype, depth + 1);
73	                H5Tclose(mtype);
74	            }
75	        }
76	        break;
77	    }
78	
79	    case H5T_ENUM: {
80	        /* Enum: valid to call H5Tget_nmembers; member values via
81	         * H5Tget_member_value; base type via H5Tget_super. */
82	        int nmembers = H5Tget_nmembers(type_id);
83	        if (nmembers < 0)
84	            break;
85	        for (int i = 0; i < nmembers; i++) {
86	            char *mname = H5Tget_member_name(type_id, (unsigned)i);
87	            if (mname)
88	                H5free_memory(mname);
89	
90	            /* H5Tget_member_value writes into caller-supplied buffer;
91	             * we pass a suitably-sized buffer for the base type. */
92	            long long val = 0;
93	            H5Tget_member_value(type_id, (unsigned)i, &val);
94	        }
95	        /* Introspect the integer base type */
96	        hid_t super = H5Tget_super(type_id);
97	        if (super >= 0) {
98	            introspect_type(super, depth + 1);
99	            H5Tclose(super);
100	        }
101	        break;
102	    }
103	
104	    case H5T_VLEN: {
105	        /* Variable-length sequence or string */
106	        htri_t is_vstr = H5Tis_variable_str(type_id);
107	        (void)is_vstr;
108	
109	        hid_t super = H5Tget_super(type_id);
110	        if (super >= 0) {
111	            introspect_type(super, depth + 1);
112	            H5Tclose(super);
113	        }
114	        break;
115	    }
116	
117	    case H5T_ARRAY: {
118	        /* Array type: ndims, dims, element type */
119	        int ndims = H5Tget_array_ndims(type_id);
120	        if (ndims > 0 && ndims <= 32) {
121	            hsize_t dims[32];
122	            H5Tget_array_dims2(type_id, dims);
123	        }
124	        hid_t super = H5Tget_super(type_id);
125	        if (super >= 0) {
126	            introspect_type(super, depth + 1);
127	            H5Tclose(super);
128	        }
129	        break;
130	    }
131	
132	    case H5T_STRING: {
133	        /* Fixed- or variable-length string */
134	        htri_t is_vstr = H5Tis_variable_str(type_id);
135	        (void)is_vstr;
136	        break;
137	    }
138	
139	    default:
140	        /* INTEGER, FLOAT, BITFIELD, OPAQUE, REFERENCE, TIME — leaf types,
141	         * no further nested APIs to call beyond get_class/get_size. */
142	        break;
143	    }
144	}
