153	/* H5Ovisit3 callback: called for every object in the file hierarchy. */
154	static herr_t visit_cb(hid_t obj_id, const char *name,
155	                        const H5O_info2_t *info, void *op_data)
156	{
157	    (void)obj_id; /* use file_id in op_data for reproducible open */
158	
159	    if (info->type != H5O_TYPE_NAMED_DATATYPE)
160	        return 0; /* only care about committed (named) types */
161	
162	    visit_data_t *vd = (visit_data_t *)op_data;
163	
164	    /* Open the committed type the same way a real application would. */
165	    hid_t type_id = H5Topen2(vd->file_id, name, H5P_DEFAULT);
166	    if (type_id < 0)
167	        return 0;
168	
169	    introspect_type(type_id, 0);
170	
171	    H5Tclose(type_id);
172	    return 0; /* continue iteration */
173	}
