175	/* --------------------------------------------------------------------- */
176	
177	int LLVMFuzzerTestOneInput(const uint8_t *data, size_t size)
178	{
179	    /* Suppress HDF5 error messages to keep output clean */
180	    H5Eset_auto2(H5E_DEFAULT, NULL, NULL);
181	
182	    char filename[64];
183	    snprintf(filename, sizeof(filename), "/tmp/h5ct_%d", getpid());
184	
185	    /* Write fuzz input to a temp file */
186	    FILE *fp = fopen(filename, "wb");
187	    if (!fp)
188	        return 0;
189	    if (size > 0)
190	        fwrite(data, 1, size, fp);
191	    fclose(fp);
192	
193	    /* Open the file read-only — a named-type reader never writes. */
194	    hid_t file_id = H5Fopen(filename, H5F_ACC_RDONLY, H5P_DEFAULT);
195	    if (file_id < 0) {
196	        unlink(filename);
197	        return 0;
198	    }
199	
200	    /* Traverse every object and exercise the type introspection APIs on
201	     * any committed (named) datatype we find. */
202	    visit_data_t vd;
203	    vd.file_id = file_id;
204	    H5Ovisit3(file_id, H5_INDEX_NAME, H5_ITER_NATIVE, visit_cb, &vd,
205	               H5O_INFO_BASIC);
206	
207	    H5Fclose(file_id);
208	    unlink(filename);
209	    return 0;
210	}
