/*
 * Fuzzing harness for committed (named) datatype open and introspection.
 *
 * Exercises: H5Topen2, H5Tget_class, H5Tget_size, H5Tget_nmembers,
 *            H5Tget_member_type, H5Tget_member_offset, H5Tis_variable_str,
 *            H5Tclose  — and supporting helpers like H5Tget_super,
 *            H5Tget_array_ndims/dims2, H5Tget_member_name.
 *
 * Attack surface: The committed-type descriptor is stored verbatim in the
 * HDF5 file and decoded on H5Topen2.  Compound, enum, vlen, and array type
 * descriptors are deeply nested and hand-parsed; historically a rich source
 * of OOB/UAF bugs.
 */

#include "hdf5.h"

#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

/* Maximum recursion depth when introspecting nested types */
#define MAX_DEPTH 8

/* Forward declaration */
static void introspect_type(hid_t type_id, int depth);

/* Recursively introspect a datatype, honouring API preconditions. */
static void introspect_type(hid_t type_id, int depth)
{
    if (depth >= MAX_DEPTH)
        return;
    if (type_id < 0)
        return;

    /* Always valid for any type */
    H5T_class_t cls  = H5Tget_class(type_id);
    size_t       sz  = H5Tget_size(type_id);
    (void)sz;

    switch (cls) {

    case H5T_COMPOUND: {
        int nmembers = H5Tget_nmembers(type_id);
        if (nmembers < 0)
            break;
        for (int i = 0; i < nmembers; i++) {
            /* H5Tget_member_name returns malloc'd string; caller must free. */
            char *mname = H5Tget_member_name(type_id, (unsigned)i);
            if (mname)
                H5free_memory(mname);

            size_t off = H5Tget_member_offset(type_id, (unsigned)i);
            (void)off;

            /* H5Tget_member_type returns a new type ID that must be closed. */
            hid_t mtype = H5Tget_member_type(type_id, (unsigned)i);
            if (mtype >= 0) {
                introspect_type(mtype, depth + 1);
                H5Tclose(mtype);
            }
        }
        break;
    }

    case H5T_ENUM: {
        /* Enum: valid to call H5Tget_nmembers; member values via
         * H5Tget_member_value; base type via H5Tget_super. */
        int nmembers = H5Tget_nmembers(type_id);
        if (nmembers < 0)
            break;
        for (int i = 0; i < nmembers; i++) {
            char *mname = H5Tget_member_name(type_id, (unsigned)i);
            if (mname)
                H5free_memory(mname);

            /* H5Tget_member_value writes into caller-supplied buffer;
             * we pass a suitably-sized buffer for the base type. */
            long long val = 0;
            H5Tget_member_value(type_id, (unsigned)i, &val);
        }
        /* Introspect the integer base type */
        hid_t super = H5Tget_super(type_id);
        if (super >= 0) {
            introspect_type(super, depth + 1);
            H5Tclose(super);
        }
        break;
    }

    case H5T_VLEN: {
        /* Variable-length sequence or string */
        htri_t is_vstr = H5Tis_variable_str(type_id);
        (void)is_vstr;

        hid_t super = H5Tget_super(type_id);
        if (super >= 0) {
            introspect_type(super, depth + 1);
            H5Tclose(super);
        }
        break;
    }

    case H5T_ARRAY: {
        /* Array type: ndims, dims, element type */
        int ndims = H5Tget_array_ndims(type_id);
        if (ndims > 0 && ndims <= 32) {
            hsize_t dims[32];
            H5Tget_array_dims2(type_id, dims);
        }
        hid_t super = H5Tget_super(type_id);
        if (super >= 0) {
            introspect_type(super, depth + 1);
            H5Tclose(super);
        }
        break;
    }

    case H5T_STRING: {
        /* Fixed- or variable-length string */
        htri_t is_vstr = H5Tis_variable_str(type_id);
        (void)is_vstr;
        break;
    }

    default:
        /* INTEGER, FLOAT, BITFIELD, OPAQUE, REFERENCE, TIME — leaf types,
         * no further nested APIs to call beyond get_class/get_size. */
        break;
    }
}

/* --------------------------------------------------------------------- */

/* op_data passed into the H5Ovisit3 callback */
typedef struct {
    hid_t file_id;
} visit_data_t;

/* H5Ovisit3 callback: called for every object in the file hierarchy. */
static herr_t visit_cb(hid_t obj_id, const char *name,
                        const H5O_info2_t *info, void *op_data)
{
    (void)obj_id; /* use file_id in op_data for reproducible open */

    if (info->type != H5O_TYPE_NAMED_DATATYPE)
        return 0; /* only care about committed (named) types */

    visit_data_t *vd = (visit_data_t *)op_data;

    /* Open the committed type the same way a real application would. */
    hid_t type_id = H5Topen2(vd->file_id, name, H5P_DEFAULT);
    if (type_id < 0)
        return 0;

    introspect_type(type_id, 0);

    H5Tclose(type_id);
    return 0; /* continue iteration */
}

/* --------------------------------------------------------------------- */

int LLVMFuzzerTestOneInput(const uint8_t *data, size_t size)
{
    /* Suppress HDF5 error messages to keep output clean */
    H5Eset_auto2(H5E_DEFAULT, NULL, NULL);

    char filename[64];
    snprintf(filename, sizeof(filename), "/tmp/h5ct_%d", getpid());

    /* Write fuzz input to a temp file */
    FILE *fp = fopen(filename, "wb");
    if (!fp)
        return 0;
    if (size > 0)
        fwrite(data, 1, size, fp);
    fclose(fp);

    /* Open the file read-only — a named-type reader never writes. */
    hid_t file_id = H5Fopen(filename, H5F_ACC_RDONLY, H5P_DEFAULT);
    if (file_id < 0) {
        unlink(filename);
        return 0;
    }

    /* Traverse every object and exercise the type introspection APIs on
     * any committed (named) datatype we find. */
    visit_data_t vd;
    vd.file_id = file_id;
    H5Ovisit3(file_id, H5_INDEX_NAME, H5_ITER_NATIVE, visit_cb, &vd,
               H5O_INFO_BASIC);

    H5Fclose(file_id);
    unlink(filename);
    return 0;
}
